// V5-PRODUCTION: 内部トークン検証（crypto依存排除版）
// ========================================
const body = $input.first().json.body || $input.first().json;
const headers = $input.first().json.headers || {};

// 環境変数必須チェック
const apiUrl = $env.N3_API_URL;
const secret = $env.N8N_INTERNAL_SECRET;
if (!apiUrl) {
  return [{ json: { error: true, message: 'N3_API_URL 環境変数が未設定です', code: 'CONFIG_ERROR' } }];
}
if (!secret) {
  return [{ json: { error: true, message: 'N8N_INTERNAL_SECRET 環境変数が未設定です', code: 'CONFIG_ERROR' } }];
}

const internalToken = headers['x-n3-signature'] || headers['X-N3-Signature'];
const tokenTimestamp = headers['x-n3-token-timestamp'] || headers['X-N3-Token-Timestamp'];
const userId = body.user_id || 'default';

// トークン検証（外部APIへ委譲）
if (internalToken && tokenTimestamp) {
  try {
    const verifyResponse = await fetch(`${apiUrl}/api/n8n-auth/verify-internal-token`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ userId, timestamp: tokenTimestamp, token: internalToken })
    });
    const verifyResult = await verifyResponse.json();

    if (!verifyResult.valid) {
      return [{ json: { error: true, message: '内部トークンが無効です', code: 'INVALID_TOKEN' } }];
    }
  } catch (e) {
    return [{ json: { error: true, message: 'トークン検証APIエラー: ' + e.message, code: 'VERIFY_API_ERROR' } }];
  }
}

// 入力検証
const productId = body.product_id;
const marketplace = body.marketplace || 'ebay_us';
const limit = body.limit || 10;
const force = body.force || false;

return [{ json: { 
  product_id: productId, 
  marketplace: marketplace, 
  user_id: userId,
  limit: limit,
  force: force,
  request_timestamp: new Date().toISOString()
} }];

// V4-PRODUCTION: エラー情報整理
const errors = $node['エラー商品取得（24hリトライ制限・user_id検証）'].json;
const errorArr = Array.isArray(errors) ? errors : [errors];
const dictArr = Array.isArray($input.first().json) ? $input.first().json : [$input.first().json];
const errorDict = dictArr.reduce((acc, e) => { if (e.error_code) acc[e.error_code] = e; return acc; }, {});

return errorArr.filter(p => p.id).map(p => {
  const info = errorDict[p.error_code] || { error_category: 'unknown', auto_recoverable: false, recovery_strategy: 'Manual review' };
  return { json: {
    user_id: p.user_id, product_id: p.id, sku: p.sku, updated_at: p.updated_at,
    title: p.english_title || p.title, category_id: p.ebay_category_id, condition: p.condition,
    price_usd: p.ddp_price_usd || p.price_usd, listing_data: p.listing_data, ebay_account: p.ebay_account,
    error_code: p.error_code, error_message: p.error_message, error_category: info.error_category,
    auto_recoverable: info.auto_recoverable, recovery_strategy: info.recovery_strategy,
    retry_count_24h: p.retry_count_24h || 0
  } };
});

// V4-PRODUCTION: AI診断結果パース＋修正適用
let ai = { diagnosis: 'Parse error', corrections: {}, confidence: 0.5, reasoning: '' };
try {
  const text = $input.first().json.text || $input.first().json.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (jsonMatch) ai = JSON.parse(jsonMatch[0]);
} catch (e) { ai.reasoning = 'AI応答パース失敗'; }

const prev = $node['1件ずつ処理'].json;
const confidence = ai.confidence || 0.5;

if (confidence < 0.6) {
  return [{ json: { ...prev, success: false, action: 'needs_review', reason: '信頼度低(' + Math.round(confidence*100) + '%)' } }];
}

// 修正データ適用
let listingData = {};
try { listingData = typeof prev.listing_data === 'string' ? JSON.parse(prev.listing_data || '{}') : (prev.listing_data || {}); } catch (e) {}

const itemSpecifics = listingData.item_specifics || {};
for (const [key, value] of Object.entries(ai.corrections || {})) {
  if (value && typeof value === 'string') itemSpecifics[key] = value;
}
if (!itemSpecifics.MPN && prev.error_category === 'item_specifics') itemSpecifics.MPN = 'Does Not Apply';
if (!itemSpecifics.Brand && prev.error_category === 'item_specifics') itemSpecifics.Brand = 'Unbranded';
listingData.item_specifics = itemSpecifics;

return [{ json: { ...prev, success: true, action: 'data_corrected', ai_diagnosis: ai, updated_listing_data: listingData, corrections: ai.corrections || {}, confidence } }];

// V4-PRODUCTION: 結果集約（圧縮）
const results = $input.all().map(i => i.json);
const recovered = results.filter(r => r.action === 'data_corrected').length;
const needsReview = results.filter(r => r.action === 'needs_review').length;
const notRecoverable = results.filter(r => r.action === 'not_auto_recoverable').length;

return [{ json: {
  success: true,
  summary: { total: results.length, recovered, needs_review: needsReview, not_recoverable: notRecoverable },
  details: results.slice(0, 10).map(r => ({ sku: r.sku, action: r.action, conf: r.confidence })),
  ts: new Date().toISOString()
} }];

// 🔐 HMAC SHA256 署名検証 (Empire OS v6)
const crypto = require('crypto');

const signature = $request.headers['x-n3-signature'] || $request.headers['X-N3-Signature'];
const timestamp = $request.headers['x-n3-timestamp'] || $request.headers['X-N3-Timestamp'];
const secret = $env.N8N_HMAC_SECRET;

if (!secret) {
  throw new Error('🚫 N8N_HMAC_SECRET 環境変数が未設定です');
}

if (!signature || !timestamp) {
  throw new Error('🚫 署名またはタイムスタンプが欠落しています');
}

// タイムスタンプ有効期限チェック (5分)
const now = Date.now();
const tsAge = now - parseInt(timestamp);
if (tsAge > 300000 || tsAge < -30000) {
  throw new Error('🚫 タイムスタンプが期限切れまたは不正です');
}

// HMAC検証
const bodyString = JSON.stringify($json);
const computedHmac = crypto
  .createHmac('sha256', secret)
  .update(timestamp + '.' + bodyString)
  .digest('hex');

if (signature !== computedHmac) {
  throw new Error('🚫 HMAC署名検証失敗: 不正なリクエスト');
}

// 検証成功 - 元データをそのまま返す
return [{ json: $json }];
